  ('bookkeeper-moex-01271', 'bookkeeper', 'bookkeeper-moex-104-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '依現行加值型及非加值型營業稅法之規定，零稅率和免稅的差別為： 零稅率的進項稅額可扣抵，免稅的進項稅額不得扣抵 零稅率的進項稅額不得扣抵，免稅的進項稅額可扣抵 零稅率和免稅的進項稅額均不得扣抵 零稅率和免稅的進項稅額均可扣抵', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:26+00:00", "source_pdf_sha1": "e11ffe57731a", "answer_pdf_sha1": "8475d4e2817c", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "602", "s": "1204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 32, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
